INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$20d48d56-679f-4ef9-9d6d-552d9f145408$tag$, $tag$2026021100260$tag$, $tag$Lucas (5531986365076)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Saber sobre os cursos","time":"11/02/2026 11:32:43"},{"role":"client","text":"🌟 Bom dia Lucas! Que alegria ter você aqui com a gente! 🙌","time":"11/02/2026 11:32:45"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"11/02/2026 11:32:48"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"11/02/2026 11:32:53"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"11/02/2026 11:33:00"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"11/02/2026 11:33:36"},{"role":"client","text":"Olá! Lucas!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"11/02/2026 11:33:38"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"11/02/2026 11:33:42"},{"role":"client","text":"Saber sobre os cursos","time":"11/02/2026 11:33:54"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"11/02/2026 11:33:59"},{"role":"client","text":"Pós-Graduação","time":"11/02/2026 11:34:10"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"11/02/2026 11:34:15"},{"role":"client","text":"Novo Testamento","time":"11/02/2026 11:36:11"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"11/02/2026 11:36:12"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"11/02/2026 11:36:16"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"11/02/2026 11:37:01"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"11/02/2026 11:37:02"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"11/02/2026 20:41:03"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n\n  *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\nTeologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações.\n\nO valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\n Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026. ","time":"11/02/2026 20:41:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nLucas, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 13:19:18"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 13:19:20"},{"role":"client","text":"Lucas, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/02/2026 13:34:20"}]$tag$, $tag$2026-02-11 11:32:43+00$tag$, FALSE, FALSE, 7.8, $tag$2026-03-01 16:42:01.563441+00$tag$, 9, 10, 9, 2, 9, 1, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$bcbe6f5d-1c3b-4374-8129-dce623c6c9c6$tag$, $tag$2026021100267$tag$, $tag$Ricardo Emilio (5521997121322)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Psicoteologia e quero mais informações.","time":"11/02/2026 11:54:42"},{"role":"client","text":"🌟 Bom dia Ricardo Emilio! Que alegria ter você aqui com a gente! 🙌","time":"11/02/2026 11:54:43"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"11/02/2026 11:54:47"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"11/02/2026 11:54:51"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"11/02/2026 11:54:58"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"11/02/2026 11:55:13"},{"role":"client","text":"Olá! Ricardo Emilio!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"11/02/2026 11:55:14"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"11/02/2026 11:55:18"},{"role":"client","text":"Saber sobre os cursos","time":"11/02/2026 11:55:33"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"11/02/2026 11:55:37"},{"role":"client","text":"Pós-Graduação","time":"11/02/2026 11:55:53"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"11/02/2026 11:55:57"},{"role":"client","text":"Psicoteologia","time":"11/02/2026 11:56:09"},{"role":"client","text":"Integra áreas do cuidado integral com a Teologia para compreender o ser humano de maneira profunda.\n 🧠 Corpo, mente e espírito.\n 📚 Forma profissionais preparados para oferecer cuidado emocional e espiritual com profundidade acadêmica e sensibilidade cristã.\n📌 Voltado para profissionais da área da saúde, teologia, aconselhamento, capelania e interessados na temática.\n🎓 Professores mestres e doutores na área.\n\n💻 Estudo online (100% EAD) e contextualizado\n","time":"11/02/2026 11:56:10"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"11/02/2026 11:56:14"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"11/02/2026 11:56:28"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"11/02/2026 11:56:29"},{"role":"client","text":"Ok","time":"11/02/2026 11:56:42"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"11/02/2026 20:41:37"},{"role":"agent","text":"*Karina Pimentel:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n******************\nDisciplinas e Professores:\n\nMódulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão\n*********\nO valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\nEsse mês esta com condições especiais com 50% de desconto e as mensalidades ficam por R$ 243,50\n\n Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, *previsto para Fevereiro 2026*!\n","time":"11/02/2026 20:42:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nRicardo Emilio, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 13:19:26"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 13:19:27"},{"role":"client","text":"Ricardo Emilio, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/02/2026 13:34:27"}]$tag$, $tag$2026-02-11 11:54:42+00$tag$, FALSE, FALSE, 7.8, $tag$2026-03-01 16:42:01.563441+00$tag$, 9, 10, 9, 2, 9, 1, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
