INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$f3480b01-1711-409f-9950-c3cb9d5a0967$tag$, $tag$2026021100328$tag$, $tag$Wendel (5524999172646)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"11/02/2026 14:19:42"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"11/02/2026 14:19:43"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"11/02/2026 20:58:22"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*\n\n🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom BOLSA10\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"11/02/2026 20:58:42","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!\nFicou alguma duvida?\nVamos prosseguir com a sua inscrição?","time":"12/02/2026 13:20:58","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Atendimento Finalizado!\n\nWendel, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 13:21:06"},{"role":"client","text":"Boa tarde! Não sem dúvidas, eu to analisando as possibilidades que tenho aqui e qual é melhor para mim, qualquer coisa eu entro em contato. Obrigado por esclarecer as dúvidas","time":"12/02/2026 13:22:05"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"15/02/2026 13:20:07"},{"role":"client","text":"Sua sessão expirou!","time":"15/02/2026 13:22:10"}]$tag$, $tag$2026-02-11 14:19:42+00$tag$, FALSE, FALSE, 7, $tag$2026-03-01 16:42:01.563441+00$tag$, 9, 10, 5, 2, 9, 2, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$24771b1f-054a-4614-bdfb-376fa272b677$tag$, $tag$2026021100334$tag$, $tag$Ruben Ribeiro (5598984559233)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá boa tarde","time":"11/02/2026 14:31:31"},{"role":"client","text":"🌟 Boa tarde Ruben Ribeiro! Que alegria ter você aqui com a gente! 🙌","time":"11/02/2026 14:31:32"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"11/02/2026 14:31:36"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"11/02/2026 14:31:40"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"11/02/2026 14:31:47"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"11/02/2026 14:32:01"},{"role":"client","text":"Olá! Ruben Ribeiro!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"11/02/2026 14:32:03"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"11/02/2026 14:32:07"},{"role":"client","text":"Outros assuntos","time":"11/02/2026 14:32:32"},{"role":"client","text":"Sem problemas!\n\nMe conta aqui com o que você precisa de ajuda, e vou te direcionar para o melhor caminho.\n","time":"11/02/2026 14:32:33"},{"role":"client","text":"Questão financeira","time":"11/02/2026 14:32:51"},{"role":"client","text":"Falar com um atendente","time":"11/02/2026 14:59:55"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"11/02/2026 20:58:59"},{"role":"agent","text":"Arquivo | (https://igrejabatista.widechat.com.br/config/storage/view/698d17d3553b87ec66070b5f)","time":"11/02/2026 20:59:16","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"É sobre o pagamento, venceu ontem, tive um problema não conseguir pagar, quero pagar hoje,mas tem a questão do desconto.","time":"11/02/2026 21:00:48"},{"role":"client","text":"Tem como dar o desconto?","time":"11/02/2026 21:01:02"},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!\n\nAgradecemos por ter aguardado até o momento.\n\nInformamos que estamos passando por um processo de transição de sistema e, por esse motivo, tivemos uma demanda elevada relacionada à emissão de boletos. No entanto, já estamos atuando ativamente para regularizar a situação de cada aluno de forma individual.\n\nMais uma vez, agradecemos pela sua paciência e compreensão.\n\nAinda hoje você receberá, em seu e-mail cadastrado, um link de pagamento com as opções de pagamento via Pix ou boleto. O e-mail será enviado pela Faculdade Internacional Cidade Viva, por meio da plataforma Sponte.\n\nGostaríamos de salientar que o seu desconto está mantido. Você não pagará juros nem multa.\n\nRessaltamos que, em um primeiro momento, o valor da parcela poderá aparecer de forma integral. No entanto, ao prosseguir para a etapa final do pagamento, seja na modalidade Pix ou boleto, o desconto de pontualidade será aplicado automaticamente, apresentando o valor correto para pagamento.\n\nFique tranquilo(a), pois o valor será ajustado corretamente no momento da finalização do pagamento.\n\nQualquer dúvida, estamos à disposição.\n\nMais uma vez, muito obrigado por aguardar.\nDeus abençoe.\n\nSecretaria Acadêmica\nFaculdade Internacional Cidade Viva","time":"12/02/2026 13:21:59","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nRuben Ribeiro, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 13:22:02"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 13:22:03"},{"role":"client","text":"Ruben Ribeiro, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/02/2026 13:37:05"}]$tag$, $tag$2026-02-11 14:31:31+00$tag$, FALSE, FALSE, 7.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 5, 2, 9, 2, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$db42fe86-a1d9-401d-aca9-af2e2e59c9cb$tag$, $tag$2026021100339$tag$, $tag$Kaique (5598982837537)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"11/02/2026 14:56:10"},{"role":"client","text":"🌟 Boa tarde Kaique! Que alegria ter você aqui com a gente! 🙌","time":"11/02/2026 14:56:12"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"11/02/2026 14:56:15"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"11/02/2026 14:56:19"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"11/02/2026 14:56:26"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"11/02/2026 14:57:09"},{"role":"client","text":"Olá! Kaique!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"11/02/2026 14:57:11"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"11/02/2026 14:57:15"},{"role":"client","text":"Falar com um atendente","time":"11/02/2026 14:57:24"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"11/02/2026 14:57:25"},{"role":"client","text":".","time":"11/02/2026 14:57:44"},{"role":"client","text":".","time":"11/02/2026 14:57:47"},{"role":"client","text":".","time":"11/02/2026 14:57:53"},{"role":"client","text":"Ontem eu esperei se resolveriam meu problema sobre o boleto que veio sem o meu desconto e não resolveu e nem fui encaminhado para secretaria e já passou do limite de pagamento(ontem), queria o meu boleto com o desconto para pagar…","time":"11/02/2026 14:58:55"},{"role":"client","text":"Pois não pagarei a multa por atraso porque não foi culpa minha. Poderia me ajudar, por gentileza ?","time":"11/02/2026 14:59:43"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"11/02/2026 20:59:24"},{"role":"client","text":"Olá","time":"11/02/2026 20:59:46"},{"role":"client","text":"Estou aguardando desde ontem. Só quero pagar o meu boleto com o meu desconto, pois o que foi enviado veio sem desconto.","time":"11/02/2026 21:00:32"},{"role":"client","text":"Bom dia","time":"12/02/2026 12:32:32"},{"role":"client","text":"Ainda estou aguardando a resposta até agora…..","time":"12/02/2026 12:32:44"},{"role":"client","text":"E não tenho nenhuma resposta","time":"12/02/2026 12:32:58"},{"role":"agent","text":"*Karina Pimentel:* Agradecemos por ter aguardado até o momento.\n\nInformamos que estamos passando por um processo de transição de sistema e, por esse motivo, tivemos uma demanda elevada relacionada à emissão de boletos. No entanto, já estamos atuando ativamente para regularizar a situação de cada aluno de forma individual.\n\nMais uma vez, agradecemos pela sua paciência e compreensão.\n\nAinda hoje você receberá, em seu e-mail cadastrado, um link de pagamento com as opções de pagamento via Pix ou boleto. O e-mail será enviado pela Faculdade Internacional Cidade Viva, por meio da plataforma Sponte.\n\nGostaríamos de salientar que o seu desconto está mantido. Você não pagará juros nem multa.\n\nRessaltamos que, em um primeiro momento, o valor da parcela poderá aparecer de forma integral. No entanto, ao prosseguir para a etapa final do pagamento, seja na modalidade Pix ou boleto, o desconto de pontualidade será aplicado automaticamente, apresentando o valor correto para pagamento.\n\nFique tranquilo(a), pois o valor será ajustado corretamente no momento da finalização do pagamento.\n\nQualquer dúvida, estamos à disposição.\n\nMais uma vez, muito obrigado por aguardar.\nDeus abençoe.\n\nSecretaria Acadêmica\nFaculdade Internacional Cidade Viva","time":"12/02/2026 15:06:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nKaique, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 15:06:17"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 15:06:18"},{"role":"client","text":"Ok. Ficarei no aguardo","time":"12/02/2026 15:07:19"},{"role":"client","text":"Opção inválida!","time":"12/02/2026 15:07:20"},{"role":"client","text":"Kaique, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/02/2026 15:22:23"}]$tag$, $tag$2026-02-11 14:56:10+00$tag$, FALSE, FALSE, 7.6, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 7, 2, 9, 1, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED