INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$04646697-c779-4b51-9e40-baf3b4c4ae87$tag$, $tag$2026021100471$tag$, $tag$Willian Borges (898595716370541)$tag$, NULL, $tag$Desconhecido$tag$, $tag$[{"role":"client","text":"Arquivo de vídeo | (https://igrejabatista.widechat.com.br/config/storage/view/698d27dc5f03e9af400c339e) | Desde sexta-feira passada... não foram liberadas minhas materias estou perdendo prazo. Tá ben difícil","time":"11/02/2026 22:07:40"},{"role":"client","text":"Olá aguarde só um momento que em breve alguém da nossa equipe irá te responder","time":"11/02/2026 22:07:41"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/02/2026 08:10:18"},{"role":"client","text":"Atendimento Finalizado!\n\nWillian Borges, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 08:10:23"}]$tag$, $tag$2026-02-11 22:07:40+00$tag$, FALSE, FALSE, 5.4, $tag$2026-03-01 16:42:01.563441+00$tag$, 5, 10, 3, 2, 7, 0, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_