INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$13348b52-5681-49ad-aee0-cf6697e3f3fc$tag$, $tag$2026021200057$tag$, $tag$Letícia (5581988364116)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"12/02/2026 09:20:45"},{"role":"client","text":"🌟 Bom dia Letícia! Que alegria ter você aqui com a gente! 🙌","time":"12/02/2026 09:20:46"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"12/02/2026 09:20:50"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"12/02/2026 09:20:54"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"12/02/2026 09:20:58"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"12/02/2026 09:21:03"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"12/02/2026 09:21:10"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"12/02/2026 09:21:11"},{"role":"client","text":"Sim, concordo","time":"12/02/2026 09:21:40"},{"role":"client","text":"✅ Obrigado, Letícia! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"12/02/2026 09:21:41"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"12/02/2026 09:21:45"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"12/02/2026 09:22:08"},{"role":"client","text":"Olá! Letícia!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"12/02/2026 09:22:09"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"12/02/2026 09:22:13"},{"role":"client","text":"Saber sobre os cursos","time":"12/02/2026 09:22:43"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"12/02/2026 09:22:47"},{"role":"client","text":"Pós-Graduação","time":"12/02/2026 09:22:58"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"12/02/2026 09:23:02"},{"role":"client","text":"Educação Cristã Clássica","time":"12/02/2026 09:23:19"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"12/02/2026 09:23:20"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"12/02/2026 09:23:24"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"12/02/2026 09:23:43"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"12/02/2026 09:23:43"},{"role":"client","text":"Gostaria de saber o valor","time":"12/02/2026 09:24:18"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/02/2026 09:30:27"},{"role":"agent","text":"*Thayanne Sales:* &nbsp;Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"12/02/2026 09:30:50","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"12/02/2026 09:31:18","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"12/02/2026 09:31:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"12/02/2026 09:32:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Essa semana está uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas R$ 239,58 \n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"12/02/2026 09:34:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Pode fazer antes de concluir a graduação?","time":"12/02/2026 10:22:05"},{"role":"agent","text":"*Thayanne Sales:* Você pode iniciar, contando que você termine a graduação, antes de terminar a pós","time":"12/02/2026 10:23:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Em caso de trancamento, como fica?","time":"12/02/2026 10:25:28"},{"role":"agent","text":"*Thayanne Sales:* Tem multa de 10% das mensalidades restantes ","time":"12/02/2026 10:26:10","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Falta quanto tempo para você concluir sua graduação?","time":"12/02/2026 10:26:23","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Estou no penúltimo período","time":"12/02/2026 10:26:43"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/698dd52f0730c3acfb068f9b) | Ficaria assim?","time":"12/02/2026 10:27:11"},{"role":"agent","text":"*Thayanne Sales:* R$ 479,16 -50% = 239,58","time":"12/02/2026 10:28:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Então da tempo, a pós inicia em abril e tem 16 meses ","time":"12/02/2026 10:29:42","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Pergunto caso eu precise tracar","time":"12/02/2026 10:31:57"},{"role":"client","text":"Gostaria de saber bem certinho em relação a isso, pois não tenho certeza de como será minha condição financeira até o fim do curso","time":"12/02/2026 10:32:41"},{"role":"client","text":"*trancar","time":"12/02/2026 10:32:48"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/698dd6ad6991382d190961ff)","time":"12/02/2026 10:33:33","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo de áudio |