INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$0d546c64-fb7c-4d34-a10d-2a60f9d5d0df$tag$, $tag$2026021200067$tag$, $tag$Mayron R (5598985269679)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia","time":"12/02/2026 09:45:55"},{"role":"client","text":"🌟 Bom dia Mayron R! Que alegria ter você aqui com a gente! 🙌","time":"12/02/2026 09:45:56"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"12/02/2026 09:46:00"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"12/02/2026 09:46:04"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"12/02/2026 09:46:11"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"12/02/2026 09:48:38"},{"role":"client","text":"Olá! Mayron R!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"12/02/2026 09:48:39"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"12/02/2026 09:48:42"},{"role":"client","text":"Outros assuntos","time":"12/02/2026 09:48:59"},{"role":"client","text":"Sem problemas!\n\nMe conta aqui com o que você precisa de ajuda, e vou te direcionar para o melhor caminho.\n","time":"12/02/2026 09:49:00"},{"role":"client","text":"Não consigo acessar a nova plataforma de pagamento e aulas. Não recebi no meu e-mail.","time":"12/02/2026 09:50:44"},{"role":"client","text":"O meu e-mail","time":"12/02/2026 09:50:46"},{"role":"client","text":"mayrong82@gmail.com","time":"12/02/2026 09:50:55"},{"role":"client","text":"Mayron Rodrigues Prazeres","time":"12/02/2026 09:50:58"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/02/2026 09:52:50"},{"role":"agent","text":"*Thayanne Sales:* Caro(a) aluno(a), bom dia.\n\nAgradecemos por ter aguardado até o momento.\n\nInformamos que estamos passando por um processo de transição de sistema e, por esse motivo, tivemos uma demanda elevada relacionada à emissão de boletos. No entanto, já estamos atuando ativamente para regularizar a situação de cada aluno de forma individual.\n\nMais uma vez, agradecemos pela sua paciência e compreensão.\n\nAinda hoje você receberá, em seu e-mail cadastrado, um link de pagamento com as opções de pagamento via Pix ou boleto. O e-mail será enviado pela Faculdade Internacional Cidade Viva, por meio da plataforma Sponte.\n\nGostaríamos de salientar que o seu desconto está mantido. Você não pagará juros nem multa.\n\nRessaltamos que, em um primeiro momento, o valor da parcela poderá aparecer de forma integral. No entanto, ao prosseguir para a etapa final do pagamento, seja na modalidade Pix ou boleto, o desconto de pontualidade será aplicado automaticamente, apresentando o valor correto para pagamento.\n\nFique tranquilo(a), pois o valor será ajustado corretamente no momento da finalização do pagamento.\n\nQualquer dúvida, estamos à disposição.\n\nMais uma vez, muito obrigado por aguardar.\nDeus abençoe.\n\nSecretaria Acadêmica\nFaculdade Internacional Cidade Viva","time":"12/02/2026 09:52:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nMayron R, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 10:05:16"},{"role":"client","text":"Atendimento Finalizado!\n\nMayron R, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 10:05:21"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 10:05:21"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"12/02/2026 10:05:22"},{"role":"client","text":"Mayron R, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"12/02/2026 10:20:23"}]$tag$, $tag$2026-02-12 09:45:55+00$tag$, FALSE, FALSE, 7.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 5, 2, 9, 1, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
