INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$bfbec92d-0acf-4477-8921-d0bc7c294bd3$tag$, $tag$2026021200101$tag$, $tag$Ana Luiza ✨ (5579991436283)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Sistematica e quero mais informações.","time":"12/02/2026 11:12:07"},{"role":"client","text":"🌟 Bom dia Ana Luiza ✨! Que alegria ter você aqui com a gente! 🙌","time":"12/02/2026 11:12:07"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"12/02/2026 11:12:11"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"12/02/2026 11:12:15"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"12/02/2026 11:12:19"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"12/02/2026 11:12:25"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"12/02/2026 11:12:31"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"12/02/2026 11:12:32"},{"role":"client","text":"Sim, concordo","time":"12/02/2026 11:13:05"},{"role":"client","text":"✅ Obrigado, Ana Luiza ✨! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"12/02/2026 11:13:06"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"12/02/2026 11:13:10"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"12/02/2026 11:13:26"},{"role":"client","text":"Olá! Ana Luiza ✨!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"12/02/2026 11:13:27"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"12/02/2026 11:13:31"},{"role":"client","text":"Saber sobre os cursos","time":"12/02/2026 11:13:44"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"12/02/2026 11:13:48"},{"role":"client","text":"Pós-Graduação","time":"12/02/2026 11:14:02"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"12/02/2026 11:14:07"},{"role":"client","text":"História do Cristianismo","time":"12/02/2026 11:14:25"},{"role":"client","text":"📜✍️ A partir da Cosmovisão Cristã Reformada, lastreada em obras de referência historiográfica e teológica, este curso apresentará os principais momentos da História do Cristianismo no Ocidente, com vistas ao enriquecimento intelectual e espiritual dos alunos, que visualizarão as rupturas e permanências em relação ao ensino e ética apostólicos ao longo dos últimos vinte séculos. Estes estudos desenvolverão o senso analítico dos alunos acerca dos mais variados movimentos religiosos do passado e presente.\n\n👨‍🏫Público alvo: Pessoas comuns, interessadas em conhecer a História do Cristianismo, a partir da Cosmovisão Cristã Reformada. Embora o alcance seja amplo, os líderes cristãos e os profissionais da Educação receberão um repertório grande de conhecimentos que trarão desenvolvimento ministerial, laboral e acadêmico.\n\n💻 Estudo online (100% EAD) e contextualizado\n","time":"12/02/2026 11:14:26"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"12/02/2026 11:14:31"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"12/02/2026 11:14:43"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"12/02/2026 11:14:44"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/02/2026 11:34:04"},{"role":"agent","text":"*Thayanne Sales:* Está pós-graduação ainda não foi lançada ","time":"12/02/2026 11:34:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Teologia sistemática está?","time":"12/02/2026 11:35:15"},{"role":"agent","text":"*Thayanne Sales:* Sim","time":"12/02/2026 11:51:00","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Valor","time":"12/02/2026 11:51:16"},{"role":"agent","text":"*Thayanne Sales:* &nbsp;*Pós-Graduação em Teologia Sistemática*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 360 h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"12/02/2026 11:54:04","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* TEOLOGIA SISTEMÁTICA - DISCIPLINAS DO CURSO:\n\nFUNDAMENTOS DA TEOLOGIA SISTEMÁTICA\nTeoria do Método Teológico e Teologia Fundamental\nTeologia Pastoral e Missiológica\nHistória da Teologia Cristã\nPerspectivas Teológico-filosóficas na pós modernidade\n\nDESDOBRAMENTOS DA TEOLOGIA SISTEMÁTICA\nTeontologia e Trindade\nCristologia\nPneumatologia e Teologia Pentecostal\nBibliologia\nAntropologia Teológica e Hamartiologia\nSoteriologia\nEclesiologia\nEscatologia\n\nObs: Professores sujeitos a alterações.","time":"12/02/2026 11:54:09","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Teologia Sistemática está em 16 mensalidades de *R$ 359,37*.\n\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"12/02/2026 11:54:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Essa semana está com uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas  R$ 179,68\n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"12/02/2026 11:54:28","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"13/02/2026 08:09:46","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Oi!! Bom dia! Ainda não!! Estou pesquisando 🤩","time":"13/02/2026 08:10:53"},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"13/02/2026 08:13:36","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não \nObrigada","time":"13/02/2026 08:14:17"},{"role":"agent","text":"*Thayanne Sales:* \nPor nada! Deus abençoe e um ótimo dia.","time":"13/02/2026 08:14:44","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nAna Luiza ✨, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"13/02/2026 08:14:49"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"13/02/2026 08:14:51"},{"role":"client","text":"Ana Luiza ✨, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"13/02/2026 08:29:55"}]$tag$, $tag$2026-02-12 11:12:07+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 9, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'