INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$bfa9b22c-620f-468f-95e8-e0b5457bf4d4$tag$, $tag$2026021200125$tag$, $tag$Pr.Rodrigo (5511959130453)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"12/02/2026 12:09:26"},{"role":"client","text":"🌟 Boa tarde Pr.Rodrigo! Que alegria ter você aqui com a gente! 🙌","time":"12/02/2026 12:09:27"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"12/02/2026 12:09:32"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"12/02/2026 12:09:36"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"12/02/2026 12:09:43"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"12/02/2026 12:10:02"},{"role":"client","text":"Olá! Pr.Rodrigo!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"12/02/2026 12:10:03"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"12/02/2026 12:10:07"},{"role":"client","text":"Falar com um atendente","time":"12/02/2026 12:10:37"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"12/02/2026 12:10:38"},{"role":"client","text":"Boleto para pagamento","time":"12/02/2026 12:10:57"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/02/2026 13:50:55"},{"role":"agent","text":"*Thayanne Sales:* Caro(a) aluno(a), boa tarde.\n\nAgradecemos por ter aguardado até o momento.\n\nInformamos que estamos passando por um processo de transição de sistema e, por esse motivo, tivemos uma demanda elevada relacionada à emissão de boletos. No entanto, já estamos atuando ativamente para regularizar a situação de cada aluno de forma individual.\n\nMais uma vez, agradecemos pela sua paciência e compreensão.\n\nAinda hoje você receberá, em seu e-mail cadastrado, um link de pagamento com as opções de pagamento via Pix ou boleto. O e-mail será enviado pela Faculdade Internacional Cidade Viva, por meio da plataforma Sponte.\n\nGostaríamos de salientar que o seu desconto está mantido. Você não pagará juros nem multa.\n\nRessaltamos que, em um primeiro momento, o valor da parcela poderá aparecer de forma integral. No entanto, ao prosseguir para a etapa final do pagamento, seja na modalidade Pix ou boleto, o desconto de pontualidade será aplicado automaticamente, apresentando o valor correto para pagamento.\n\nFique tranquilo(a), pois o valor será ajustado corretamente no momento da finalização do pagamento.\n\nQualquer dúvida, estamos à disposição.\n\nMais uma vez, muito obrigado por aguardar.\nDeus abençoe.\n\nSecretaria Acadêmica\nFaculdade Internacional Cidade Viva","time":"12/02/2026 13:51:09","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nPr.Rodrigo, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"13/02/2026 08:09:52"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"13/02/2026 08:09:53"},{"role":"client","text":"Pr.Rodrigo, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"13/02/2026 08:24:53"}]$tag$, $tag$2026-02-12 12:09:26+00$tag$, FALSE, FALSE, 7.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 5, 2, 9, 1, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$09e4d200-1966-492b-b9ba-338146f7499f$tag$, $tag$2026021200126$tag$, $tag$eu estou aqui (5583991407202)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"não","time":"12/02/2026 12:10:08"},{"role":"client","text":"🌟 Boa tarde eu estou aqui! Que alegria ter você aqui com a gente! 🙌","time":"12/02/2026 12:10:09"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"12/02/2026 12:10:13"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"12/02/2026 12:10:18"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"12/02/2026 12:10:22"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"12/02/2026 12:10:27"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"12/02/2026 12:10:33"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"12/02/2026 12:10:34"},{"role":"client","text":"Sim, concordo","time":"12/02/2026 12:11:20"},{"role":"client","text":"✅ Obrigado, eu estou aqui! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"12/02/2026 12:11:21"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"12/02/2026 12:11:25"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"12/02/2026 12:11:41"},{"role":"client","text":"Olá! eu estou aqui!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"12/02/2026 12:11:42"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"12/02/2026 12:11:47"},{"role":"client","text":"Saber sobre os cursos","time":"12/02/2026 12:12:04"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"12/02/2026 12:12:08"},{"role":"client","text":"Graduação","time":"12/02/2026 12:12:22"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"12/02/2026 12:12:26"},{"role":"client","text":"Direito (Presencial)","time":"12/02/2026 12:12:40"},{"role":"client","text":"Excelente escolha! O curso de Direito da FICV é presencial em João Pessoa, tem nota máxima no MEC, prática jurídica desde o primeiro período e bolsa de 60% em todas as mensalidades!\n","time":"12/02/2026 12:12:40"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"12/02/2026 12:12:44"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"12/02/2026 12:13:02"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"12/02/2026 12:13:03"},{"role":"client","text":"ok","time":"12/02/2026 12:13:20"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/02/2026 14:13:35"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"12/02/2026 14:13:50","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"12/02/2026 14:13:59","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*","time":"12/02/2026 14:14:05","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação em Direito está R$ 1.689,54. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 675,81.\n\n✨Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"12/02/2026 14:14:11","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"12/02/2026 14:14:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"13/02/2026 08:10:10","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\neu estou aqui, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"13/02/2026 13:40:49"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"13/02/2026 13:40:50"},{"role":"client","text":"eu estou aqui, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"13/02/2026 13:55:50"}]$tag$, $tag$2026-02-12 12:10:08+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 6, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$442d2440-bba6-42af-9d2c-e6a5a02d4faf$tag$, $tag$2026021200127$tag$, $tag$Patricia Lemes (5514997205399)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"12/02/2026 12:10:45"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"12/02/2026 12:10:46"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/02/2026 14:08:36"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"12/02/2026 14:08:59","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"12/02/2026 14:09:31","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"12/02/2026 14:09:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 431,67 por mês!\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"12/02/2026 14:09:42","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 431,67 por mês!\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"12/02/2026 14:09:49","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Eu gostaria de saber mais sobre o curso. É de linha reformada ou interdenominacional?","time":"12/02/2026 14:12:16"},{"role":"agent","text":"*Thayanne Sales:* A nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"12/02/2026 14:13:21","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Tenho interesse\nQuais seriam as datas para pagto ? A mensalidade é livre de reajuste anual?","time":"12/02/2026 14:22:30"},{"role":"agent","text":"*Thayanne Sales:*  o desconto é de pontualidade para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio.","time":"12/02/2026 14:29:09","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Tem reajuste anual nas mensalidades ","time":"12/02/2026 14:29:22","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Certo, obg","time":"12/02/2026 14:39:36"},{"role":"agent","text":"*Thayanne Sales:* Vamos prosseguir com a sua matricula?","time":"12/02/2026 14:48:22","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Vou conversar com meu esposo sobre os valores","time":"12/02/2026 15:18:53"},{"role":"client","text":"Dpois entro em contato cm vcs novamente","time":"12/02/2026 15:19:01"},{"role":"agent","text":"*Thayanne Sales:* Compreendo","time":"12/02/2026 15:24:38","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Ta certo","time":"12/02/2026 15:24:41","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConversou com seu esposo?","time":"13/02/2026 08:11:06","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Conversei sim, estamos nos planejando. Estou aguardando a resposta dele sobre","time":"13/02/2026 09:24:56"},{"role":"client","text":"Mas acho que vou fazer sim","time":"13/02/2026 09:25:04"},{"role":"agent","text":"*Thayanne Sales:* Compreendo","time":"13/02/2026 09:40:43","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"13/02/2026 09:41:01","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Por enquanto não","time":"13/02/2026 09:58:38"},{"role":"agent","text":"*Thayanne Sales:* \nPor nada! Deus abençoe e um ótimo dia.","time":"13/02/2026 09:59:21","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nPatricia Lemes, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa fu