INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$28d0975e-ffce-49d6-b69f-945f083cae63$tag$, $tag$2026021200182$tag$, $tag$FERNANDO DOS SANTOS BATISTA (5583988386596)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"12/02/2026 14:59:52"},{"role":"client","text":"🌟 Boa tarde FERNANDO DOS SANTOS BATISTA! Que alegria ter você aqui com a gente! 🙌","time":"12/02/2026 14:59:53"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"12/02/2026 14:59:57"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"12/02/2026 15:00:01"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"12/02/2026 15:00:04"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"12/02/2026 15:00:10"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"12/02/2026 15:00:16"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"12/02/2026 15:00:17"},{"role":"client","text":"Sim, concordo","time":"12/02/2026 15:00:30"},{"role":"client","text":"✅ Obrigado, FERNANDO DOS SANTOS BATISTA! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"12/02/2026 15:00:33"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"12/02/2026 15:00:37"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"12/02/2026 15:00:53"},{"role":"client","text":"Olá! FERNANDO DOS SANTOS BATISTA!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"12/02/2026 15:00:54"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"12/02/2026 15:00:59"},{"role":"client","text":"Falar com um atendente","time":"12/02/2026 15:01:12"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"12/02/2026 15:01:13"},{"role":"client","text":"Pagamento","time":"12/02/2026 15:01:31"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/02/2026 15:25:25"},{"role":"agent","text":"*Thayanne Sales:* Caro(a) aluno(a), boa tarde.\n\nAgradecemos por ter aguardado até o momento.\n\nInformamos que estamos passando por um processo de transição de sistema e, por esse motivo, tivemos uma demanda elevada relacionada à emissão de boletos. No entanto, já estamos atuando ativamente para regularizar a situação de cada aluno de forma individual.\n\nMais uma vez, agradecemos pela sua paciência e compreensão.\n\nAinda hoje você receberá, em seu e-mail cadastrado, um link de pagamento com as opções de pagamento via Pix ou boleto. O e-mail será enviado pela Faculdade Internacional Cidade Viva, por meio da plataforma Sponte.\n\nGostaríamos de salientar que o seu desconto está mantido. Você não pagará juros nem multa.\n\nRessaltamos que, em um primeiro momento, o valor da parcela poderá aparecer de forma integral. No entanto, ao prosseguir para a etapa final do pagamento, seja na modalidade Pix ou boleto, o desconto de pontualidade será aplicado automaticamente, apresentando o valor correto para pagamento.\n\nFique tranquilo(a), pois o valor será ajustado corretamente no momento da finalização do pagamento.\n\nQualquer dúvida, estamos à disposição.\n\nMais uma vez, muito obrigado por aguardar.\nDeus abençoe.","time":"12/02/2026 15:25:36","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nFERNANDO DOS SANTOS BATISTA, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"13/02/2026 08:11:16"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"13/02/2026 08:11:17"},{"role":"client","text":"FERNANDO DOS SANTOS BATISTA, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"13/02/2026 08:26:19"}]$tag$, $tag$2026-02-12 14:59:52+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 9, 2, 9, 1, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_sco