INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$4b71309d-8d15-4709-b9e9-da34be333992$tag$, $tag$2026021200186$tag$, $tag$Dr hc Reginaldo Sousa (5591982346602)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"12/02/2026 15:20:02"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"12/02/2026 15:20:03"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/02/2026 15:27:13"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"12/02/2026 15:27:28","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"12/02/2026 15:27:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"12/02/2026 15:27:43","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 431,67 por mês!\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"12/02/2026 15:27:50","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.\n","time":"12/02/2026 15:27:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thay